  1	import * as React from 'react';
  2	import {
  3	  FormGroup,
  4	  FormHelperText,
  5	  FormSelect,
  6	  FormSelectOption,
  7	  HelperText,
  8	  HelperTextItem,
  9	  Switch,
 10	  TextInput
 11	} from '@patternfly/react-core';
 12	import { RuleBuilder, Rule } from './AuthorizationPolicyForm/RuleBuilder';
 13	import { RuleList } from './AuthorizationPolicyForm/RuleList';
 14	import { isValid } from 'utils/Common';
 15	import { t, useKialiTranslation } from 'utils/I18nUtils';
 16	
 17	export type AuthorizationPolicyState = {
 18	  action: string;
 19	  addWorkloadSelector: boolean;
 20	  // Used to identify DENY_ALL, ALLOW_ALL or RULES
 21	  policy: string;
 22	  rules: Rule[];
 23	  workloadSelector: string;
 24	  workloadSelectorValid: boolean;
 25	};
 26	
 27	type Props = {
 28	  authorizationPolicy: AuthorizationPolicyState;
 29	  onChange: (authorizationPolicy: AuthorizationPolicyState) => void;
 30	};
 31	
 32	export const DENY_ALL = 'DENY_ALL';
 33	export const ALLOW_ALL = 'ALLOW_ALL';
 34	export const RULES = 'RULES';
 35	export const ALLOW = 'ALLOW';
 36	export const DENY = 'DENY';
 37	
 38	const HELPER_TEXT = {
 39	  ALLOW_ALL: t('Allows all requests to workloads in given namespace(s)'),
 40	  DENY_ALL: t('Denies all requests to workloads in given namespace(s)'),
 41	  RULES: t('Builds an Authorization Policy based on Rules')
 42	};
 43	
 44	const rulesFormValues = [DENY_ALL, ALLOW_ALL, RULES];
 45	
 46	const actions = [ALLOW, DENY];
 47	
 48	export const initAuthorizationPolicy = (): AuthorizationPolicyState => ({
 49	  policy: DENY_ALL,
 50	  workloadSelector: '',
 51	  action: ALLOW,
 52	  rules: [],
 53	  addWorkloadSelector: false,
 54	  workloadSelectorValid: false
 55	});
 56	
 57	export const isAuthorizationPolicyStateValid = (ap: AuthorizationPolicyState): boolean => {
 58	  const workloadSelectorRule = ap.addWorkloadSelector ? ap.workloadSelectorValid : true;
 59	  const denyRule = ap.action === DENY ? ap.rules.length > 0 : true;
 60	
 61	  return workloadSelectorRule && denyRule;
 62	};
 63	
 64	export const AuthorizationPolicyForm: React.FC<Props> = (props: Props) => {
 65	  const { t } = useKialiTranslation();
 66	
 67	  const {
 68	    action,
 69	    addWorkloadSelector,
 70	    policy,
 71	    rules,
 72	    workloadSelector,
 73	    workloadSelectorValid
 74	  } = props.authorizationPolicy;
 75	
 76	  const onRulesFormChange = (_event: React.FormEvent, value: string): void => {
 77	    onAuthorizationChange({ policy: value });
 78	  };
 79	
 80	  const onChangeWorkloadSelector = (_event: React.FormEvent, value: boolean): void => {
 81	    onAuthorizationChange({ addWorkloadSelector: value });
 82	  };
 83	
 84	  const addWorkloadLabels = (_event: React.FormEvent, value: string): void => {
 85	    if (value.length === 0) {
 86	      onAuthorizationChange({ workloadSelector: '', workloadSelectorValid: false });
 87	
 88	      return;
 89	    }
 90	
 91	    value = value.trim();
 92	    const labels: string[] = value.split(',');
 93	    let isValid = true;
 94	
 95	    // Some smoke validation rules for the labels
 96	    for (let i = 0; i < labels.length; i++) {
 97	      const label = labels[i];
 98	
 99	      if (label.indexOf('=') < 0) {
100	        isValid = false;
101	        break;
102	      }
103	
104	      const splitLabel: string[] = label.split('=');
105	
106	      if (splitLabel.length !== 2) {
107	        isValid = false;
108	        break;
109	      }
110	
111	      if (splitLabel[0].trim().length === 0 || splitLabel[1].trim().length === 0) {
112	        isValid = false;
113	        break;
114	      }
115	    }
116	
117	    onAuthorizationChange({ workloadSelector: value, workloadSelectorValid: isValid });
118	  };
119	
120	  const onActionChange = (_event: React.FormEvent, value: string): void => {
121	    onAuthorizationChange({ action: value });
122	  };
123	
124	  const onAddRule = (rule: Rule): void => {
125	    const newRules = [...rules];
126	    newRules.push(rule);
127	
128	    onAuthorizationChange({ rules: newRules });
129	  };
130	
131	  const onRemoveRule = (index: number): void => {
132	    const newRules = [...rules];
133	    newRules.splice(index, 1);
134	
135	    onAuthorizationChange({ rules: newRules });
136	  };
137	
138	  const onAuthorizationChange = (authorizationPolicy: Partial<AuthorizationPolicyState>): void => {
139	    props.onChange({ ...props.authorizationPolicy, ...authorizationPolicy });
140	  };
141	
142	  return (
143	    <>
144	      <FormGroup label={t('Policy')} fieldId="rules-form">
145	        <FormSelect value={policy} onChange={onRulesFormChange} id="rules-form" name="rules-form">
146	          {rulesFormValues.map((option, index) => (
147	            <FormSelectOption key={index} value={option} label={option} />
148	          ))}
149	        </FormSelect>
150	        <FormHelperText>
151	          <HelperText>
152	            <HelperTextItem>{t(HELPER_TEXT[policy])}</HelperTextItem>
153	          </HelperText>
154	        </FormHelperText>
155	      </FormGroup>
156	
157	      {policy === RULES && (
158	        <FormGroup label={t('Workload Selector')} fieldId="workloadSelectorSwitch">
159	          <Switch
160	            id="workloadSelectorSwitch"
161	            label=" "
162	
163	            isChecked={addWorkloadSelector}
164	            onChange={onChangeWorkloadSelector}
165	          />
166	        </FormGroup>
167	      )}
168	
169	      {addWorkloadSelector && (
170	        <FormGroup label={t('Labels')} fieldId="workloadLabels">
171	          <TextInput
172	            id="gwHosts"
173	            name="gwHosts"
174	            isDisabled={!addWorkloadSelector}
175	            value={workloadSelector}
176	            onChange={addWorkloadLabels}
177	            validated={isValid(workloadSelectorValid)}
178	          />
179	
180	          <FormHelperText>
181	            <HelperText>
182	              <HelperTextItem>
183	                {isValid(workloadSelectorValid)
184	                  ? t('One or more labels to select a workload where the AuthorizationPolicy is applied.')
185	                  : t('Enter a label in the format <label>=<value>. Enter one or multiple labels separated by comma.')}
186	              </HelperTextItem>
187	            </HelperText>
188	          </FormHelperText>
189	        </FormGroup>
190	      )}
191	
192	      {policy === RULES && (
193	        <FormGroup label={t('Action')} fieldId="action-form">
194	          <FormSelect value={action} onChange={onActionChange} id="action-form" name="action-form">
195	            {actions.map((option, index) => (
196	              <FormSelectOption key={index} value={option} label={option} />
197	            ))}
198	          </FormSelect>
199	        </FormGroup>
200	      )}
201	
202	      {policy === RULES && <RuleBuilder onAddRule={onAddRule} />}
203	
204	      {policy === RULES && (
205	        <FormGroup label={t('Rule List')} fieldId="apRuleList">
206	          <RuleList action={action} ruleList={rules} onRemoveRule={onRemoveRule} />
207	        </FormGroup>
208	      )}
209	    </>
210	  );
211	};

