 64	export const AuthorizationPolicyForm: React.FC<Props> = (props: Props) => {
 65	  const { t } = useKialiTranslation();
 66	
 67	  const {
 68	    action,
 69	    addWorkloadSelector,
 70	    policy,
 71	    rules,
 72	    workloadSelector,
 73	    workloadSelectorValid
 74	  } = props.authorizationPolicy;
 75	
 76	  const onRulesFormChange = (_event: React.FormEvent, value: string): void => {
 77	    onAuthorizationChange({ policy: value });
 78	  };
 79	
 80	  const onChangeWorkloadSelector = (_event: React.FormEvent, value: boolean): void => {
 81	    onAuthorizationChange({ addWorkloadSelector: value });
 82	  };
 83	
 84	  const addWorkloadLabels = (_event: React.FormEvent, value: string): void => {
 85	    if (value.length === 0) {
 86	      onAuthorizationChange({ workloadSelector: '', workloadSelectorValid: false });
 87	
 88	      return;
 89	    }
 90	
 91	    value = value.trim();
 92	    const labels: string[] = value.split(',');
 93	    let isValid = true;
 94	
 95	    // Some smoke validation rules for the labels
 96	    for (let i = 0; i < labels.length; i++) {
 97	      const label = labels[i];
 98	
 99	      if (label.indexOf('=') < 0) {
100	        isValid = false;
101	        break;
102	      }
103	
104	      const splitLabel: string[] = label.split('=');
105	
106	      if (splitLabel.length !== 2) {
107	        isValid = false;
108	        break;
109	      }
110	
111	      if (splitLabel[0].trim().length === 0 || splitLabel[1].trim().length === 0) {
112	        isValid = false;
113	        break;
114	      }
115	    }
116	
117	    onAuthorizationChange({ workloadSelector: value, workloadSelectorValid: isValid });
118	  };
119	
120	  const onActionChange = (_event: React.FormEvent, value: string): void => {
121	    onAuthorizationChange({ action: value });
122	  };
123	
124	  const onAddRule = (rule: Rule): void => {
125	    const newRules = [...rules];
126	    newRules.push(rule);
127	
128	    onAuthorizationChange({ rules: newRules });
129	  };
130	
131	  const onRemoveRule = (index: number): void => {
132	    const newRules = [...rules];
133	    newRules.splice(index, 1);
134	
135	    onAuthorizationChange({ rules: newRules });
136	  };
137	
138	  const onAuthorizationChange = (authorizationPolicy: Partial<AuthorizationPolicyState>): void => {
139	    props.onChange({ ...props.authorizationPolicy, ...authorizationPolicy });
140	  };
141	
142	  return (
143	    <>
144	      <FormGroup label={t('Policy')} fieldId="rules-form">
145	        <FormSelect value={policy} onChange={onRulesFormChange} id="rules-form" name="rules-form">
146	          {rulesFormValues.map((option, index) => (
147	            <FormSelectOption key={index} value={option} label={option} />
148	          ))}
149	        </FormSelect>
150	        <FormHelperText>
151	          <HelperText>
152	            <HelperTextItem>{t(HELPER_TEXT[policy])}</HelperTextItem>
153	          </HelperText>
154	        </FormHelperText>
155	      </FormGroup>
156	
157	      {policy === RULES && (
158	        <FormGroup label={t('Workload Selector')} fieldId="workloadSelectorSwitch">
159	          <Switch
160	            id="workloadSelectorSwitch"
161	            label=" "
162	            isChecked={addWorkloadSelector}
163	            onChange={onChangeWorkloadSelector}
164	          />
165	        </FormGroup>
166	      )}
167	
168	      {addWorkloadSelector && (
169	        <FormGroup label={t('Labels')} fieldId="workloadLabels">
170	          <TextInput
171	            id="gwHosts"
172	            name="gwHosts"
173	            isDisabled={!addWorkloadSelector}
174	            value={workloadSelector}
175	            onChange={addWorkloadLabels}
176	            validated={isValid(workloadSelectorValid)}
177	          />
178	
179	          <FormHelperText>
180	            <HelperText>
181	              <HelperTextItem>
182	                {isValid(workloadSelectorValid)
183	                  ? t('One or more labels to select a workload where the AuthorizationPolicy is applied.')
184	                  : t('Enter a label in the format <label>=<value>. Enter one or multiple labels separated by comma.')}
185	              </HelperTextItem>
186	            </HelperText>
187	          </FormHelperText>
188	        </FormGroup>
189	      )}
190	
191	      {policy === RULES && (
192	        <FormGroup label={t('Action')} fieldId="action-form">
193	          <FormSelect value={action} onChange={onActionChange} id="action-form" name="action-form">
194	            {actions.map((option, index) => (
195	              <FormSelectOption key={index} value={option} label={option} />
196	            ))}
197	          </FormSelect>
198	        </FormGroup>
199	      )}
200	
201	      {policy === RULES && <RuleBuilder onAddRule={onAddRule} />}
202	
203	      {policy === RULES && (
204	        <FormGroup label={t('Rule List')} fieldId="apRuleList">
205	          <RuleList action={action} ruleList={rules} onRemoveRule={onRemoveRule} />
206	        </FormGroup>
207	      )}
208	    </>
209	  );
210	};
